import { NgModule } from '@angular/core';
import { Routes, RouterModule } from '@angular/router';
import { AuthGuard } from '../api/guard/auth-guard.guard';
import { GlobalAuthGuard } from '../api/guard/global-auth-guard.guard';
import { RestrictedComponent } from './restricted/restricted.component';

const routes: Routes = [
  { path: '', 
    loadChildren: () =>
      import('./login/login.module').then((m) => m.LoginModule), },
  {
    path: '',
    component: RestrictedComponent,
    canActivate: [AuthGuard],
    children: [
      {
        path: 'home',
        loadChildren: () =>
          import('./restricted/home/home.module').then((m) => m.HomeModule),
      },
      {
        path: 'admin-profile',
        loadChildren: () =>
          import('./restricted/admin-profile/admin-profile.module').then(
            (m) => m.AdminProfileModule
          ),
      },
      {
        path: 'admin-users',
        canActivate: [GlobalAuthGuard],
        loadChildren: () =>
          import('./restricted/admin-users/admin-users.module').then(
            (m) => m.AdminUsersModule
          ),
      },
      {
        path: 'brands',
        loadChildren: () =>
          import('./restricted/brands/brands.module').then(
            (m) => m.BrandsModule
          ),
      },

      {
        path: 'stats',
        loadChildren: () =>
          import('./restricted/stats/stats.module').then((m) => m.StatsModule),
      },
      {
        path: 'system-settings',
        canActivate: [GlobalAuthGuard],
        loadChildren: () =>
          import('./restricted/system-settings/system-settings.module').then(
            (m) => m.SystemSettingsModule
          ),
      },
    ],
  }
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule],
})
export class LayoutRoutingModule {}
