import { AuthService, User } from 'src/app/api/auth/auth.service';

import { MatTableDataSource } from '@angular/material/table';
import { Component, OnInit, ViewChild } from '@angular/core';
import { MatPaginator } from '@angular/material/paginator';
export interface TableInfo {
  title: string;
  info: string;
}

@Component({
  selector: 'app-admin-profile',
  templateUrl: './admin-profile.component.html',
  styleUrls: ['./admin-profile.component.scss']
})
export class AdminProfileComponent implements OnInit {
  displayedColumns: string[] = ['title', 'info',];

  dataSource: MatTableDataSource<TableInfo> = null;
  user: User;

  @ViewChild(MatPaginator) paginator: MatPaginator;
  constructor(private auth: AuthService) { }

  ngOnInit(): void {
    this.user = this.auth.getUser();
    var data: TableInfo[] = [{title: "Name:", info: this.user.name}, {title: "Email:", info: this.user.email} ];
    this.dataSource = new MatTableDataSource<TableInfo>(data);
    this.dataSource.paginator = this.paginator;
  }

}
