import { Injectable } from "@angular/core";
import { AngularFirestore, AngularFirestoreCollection } from "@angular/fire/firestore";

export interface QRInfo {
  clientId: number;
  productId: string; 
  brandId: string;
}
export interface ProductQRInfo {
  clientId: number;
  qrId: string;  
}
@Injectable({
    providedIn: 'root',
})
export class QRService {
  collectionReference: AngularFirestoreCollection;
  
  constructor(private angularFirestore: AngularFirestore) {
    this.collectionReference = angularFirestore.collection("qrcodes");
  }

  async addQRCode(clientId: number, productId: string, brandId: string) {
    const qrInfo = {clientId, productId, brandId};
    return this.collectionReference.add(qrInfo).then(doc => {
      return {clientId, qrId: doc.id} as ProductQRInfo;
    });
  }
}