import { AfterViewInit, Component, ElementRef, Inject, OnInit, ViewChild } from '@angular/core';
import { MatDialogRef, MAT_DIALOG_DATA } from '@angular/material/dialog';
import { BrandsComponent } from '../brands.component';

@Component({
    selector: 'app-product-pop-up',
    templateUrl: './brand-pop-up.component.html',
    styleUrls: ['./brand-pop-up.component.scss'],
  })
  export class BrandPopUpComponent implements AfterViewInit {
    
    @ViewChild('nameInput') nameInput: ElementRef;
    name: string;
    title: string = "Add Brand";
  
    constructor(private dialogRef : MatDialogRef<BrandsComponent>, @Inject(MAT_DIALOG_DATA) public data) {
      if (data != null) {
        this.title = "Edit Brand";
        this.name = data.name;
      }
    }
    
    ngAfterViewInit(): void {
      if (this.name) {
        this.nameInput.nativeElement.value = this.name;
      }
    }

    submit() {
      this.dialogRef.close(this.nameInput.nativeElement.value);
    }
  }