import {Inject, Injectable} from '@angular/core';
import { AngularFireAuth } from '@angular/fire/auth';
import { Router } from '@angular/router';
import { throwError } from 'rxjs';
import { catchError, tap } from 'rxjs/operators';
import { environment } from 'src/environments/environment';
import { UserService } from '../user/user.service';

export interface Login {
  email: string;
  password: string;
}

export class User {
  id?: string;
  name: string;
  email: string;
  imagePath: string;
  role: string;
  phone?: string;
  isEditUser?: boolean;
  adminBrands?: string[];
}

@Injectable({
  providedIn: 'root',
})
export class AuthService {
  user: User;

  constructor(public afAuth: AngularFireAuth, public userService: UserService, public  router:  Router) { }

  public async logIn(email, password) {
    const result = await this.afAuth.signInWithEmailAndPassword(email, password);
    await this.userService.getUser(result.user.uid).subscribe(subUser => {
      if (subUser.role === 'admin' || subUser.role === 'global-admin' ) {
        this.user = { ...subUser, id: result.user.uid};
        localStorage.setItem('user', JSON.stringify(this.user));
        this.router.navigate(['/brands']);
      }
    }); 
    
  }

  get isLoggedIn(): boolean {
    const user: User = JSON.parse(localStorage.getItem('user'));
    return user !== null;
  }

  get isGlobalAdminLoggedIn(): boolean {
    const user: User = JSON.parse(localStorage.getItem('user'));
    return user.role === "global-admin";
  }
  
  public getUser() {
    const user: User = JSON.parse(localStorage.getItem('user'));
    return user;
  }

  public async logOut() {
    await this.afAuth.signOut();
    localStorage.removeItem('user');
    this.router.navigate(['']);
  }

  public deleteUser(user: User) {
    // TO-DO: Delete user from Authentication
    this.userService.deleteUser(user);
  }

  public async createUser(user) {
    var result = await this.afAuth.createUserWithEmailAndPassword(user.email, '12345678');
    return this.userService.createUser({...user, id: result.user.uid, userBrands: []});
  }

  public updateUser(user) {
    this.user = user;
    localStorage.setItem('user', JSON.stringify(user));
  }

  private formatErrors(error: any) {
    console.log('THIS IS THE ERROR : ');
    return throwError(error.error);
  }
}
