import { Injectable } from '@angular/core';
import { AngularFirestore, AngularFirestoreCollection, QuerySnapshot } from '@angular/fire/firestore';
import { throwError } from 'rxjs';
import { catchError, map } from 'rxjs/operators';
import { AuthService } from '../auth/auth.service';
import { UserService } from '../user/user.service';
import firebase from 'firebase';
import { Node } from 'src/app/layout/restricted/brands/nodes/nodes.component';
import { Category, Product } from 'src/app/layout/restricted/brands/products-and-categories/products-and-categories.component';
import { FileService } from '../file/file.service';
import { ProductQRInfo, QRService } from '../qr/qr.service';

export interface Brand {
  id: string;
  name: string;
  adminId: string;
  nodes: Node[];
  category?: Category;
}

@Injectable({
  providedIn: 'root',
})
export class BrandService {
  collectionReference: AngularFirestoreCollection;
  
  constructor(private angularFirestore: AngularFirestore, 
    public authService: AuthService, 
    public userService: UserService,
    public fileService: FileService,
    public qrService: QRService,
  ) {
    this.collectionReference = angularFirestore.collection("brands");
  }

  getProductsCollectionRef(brandId: string) {
    return this.collectionReference.doc(brandId).collection("products");
  }

  async createBrand(name) {
    const user = this.authService.getUser();
    const brand = {adminId: user.id, name, nodes: [], category: {categories: [], products: []}};
    return this.collectionReference.add(brand).then(doc => {
      this.userService.addBrandToUser(doc.id, user.id);
      this.authService.updateUser({...user, adminBrands: [...user.adminBrands, doc.id]});
      return {...brand, id: doc.id} as Brand
    });
  }

  async editBrand(brand: Brand) {
    return this.collectionReference.doc(brand.id).update(brand);
  }

  getBrands() {
    const user = this.authService.getUser();
    if (user.role == 'admin') {
      if (user.adminBrands.length > 0) {
        return this.angularFirestore
              .collection("brands", ref => ref.where(firebase.firestore.FieldPath.documentId(), 'in', user.adminBrands))
              .get().pipe(
                map((docs: QuerySnapshot<any>) => {
                  return docs.docs.map(e => {
                    return {
                      ...e.data(),
                      id: e.id
                    } as Brand;
                  });
                })
              );
      } else {
        return null;
      }
    } else {
      return this.collectionReference
      .get().pipe(
        map((docs: QuerySnapshot<any>) => {
          return docs.docs.map(e => {
            return {
              ...e.data(),
              id: e.id
            } as Brand;
          });
        })
      );
    }
  }

  getBrand(brandId: string) {
    return this.collectionReference.doc<Brand>(brandId).valueChanges();
  }

  getBrandProducts(brandId: string) {
    return this.getProductsCollectionRef(brandId).get().pipe(
      map((docs: QuerySnapshot<any>) => {
        return docs.docs.map(e => {
          return {
            ...e.data(),
            id: e.id,
          } as Product;
        });
      })
    );;
  }

  async addNode(brand: Brand, node: Node, file: File): Promise<Node> {
    if (file != null) {
      return this.fileService.uploadNodeFile(brand.id, file).then(async (path) => {
          return await this.editBrand({...brand, nodes: [...brand.nodes, {...node, certificatePath: path}]}).then(() => {
            return {...node, certificatePath: path};
          });
      });
    } else {
      const updatedNode: Node = {...node, certificatePath: ""};
      this.editBrand({...brand, nodes: [...brand.nodes, updatedNode]});
      return updatedNode;
    }
  }

  deleteNode(brand: Brand, node: Node) {
    const nodes: Node[] = [...brand.nodes];
    nodes.splice(nodes.indexOf(node), 1);
    if (node.certificatePath !== "") {
      this.fileService.deleteFile(node.certificatePath);
    }
    this.editBrand({...brand, nodes});
  }

  async updateNode(brand: Brand, oldNode:Node, newNode: Node, file: File): Promise<Node> {
    const nodes: Node[] = [...brand.nodes];
    nodes.splice(nodes.indexOf(oldNode), 1);
    if (file != null) {
      return this.fileService.uploadNodeFile(brand.id, file).then((path) => {
          return this.editBrand({...brand, nodes: [...nodes, {...newNode, certificatePath: path}]}).then(() => {
            return {...newNode, certificatePath: path};
          })
      });
    } else {
      const updatedNode: Node = {...newNode};
      this.editBrand({...brand, nodes: [...nodes, updatedNode]});
      return updatedNode;
    }
  }

  async updateBrandCategory(brand: Brand, categories: Category[]) {
    return this.editBrand({...brand, category: {...brand.category, categories: categories}});
  }

  async addProduct(brand: Brand, product: Product, pictureFiles: File[], videoFile: File) {
    if (videoFile != null) {
          return this.getProductsCollectionRef(brand.id).add({...product, brandId: brand.id}).then(doc => {
            return this.fileService.uploadProductFile(brand.id, videoFile, product.id)
              .then(videoPath => {
                const picturePaths: string[] = [];
                if (pictureFiles.length > 0) {
                  pictureFiles
                    .forEach(async file => await this.fileService.uploadProductFile(brand.id, file, doc.id)
                    .then(path => {
                      picturePaths.push(path);
                      if (pictureFiles.indexOf(file) === pictureFiles.length - 1) {
                        this.updateProduct(brand, {...product, id: doc.id, picturePaths: [...picturePaths, ...product.picturePaths], videoPath });
                      }
                    })
                  );
                }
                return {...product, id: doc.id,  picturePaths: [...picturePaths, ...product.picturePaths], videoPath } as Product;
              });
          });
    } else {
      return this.getProductsCollectionRef(brand.id).add({...product, brandId: brand.id}).then(doc => {
        const picturePaths: string[] = [];
        if (pictureFiles.length > 0) {
          pictureFiles
            .forEach(async file => await this.fileService.uploadProductFile(brand.id, file, doc.id)
            .then(path => {
              picturePaths.push(path);
              if (pictureFiles.indexOf(file) === pictureFiles.length - 1) {
                this.updateProduct(brand, {...product, id: doc.id,  picturePaths: [...picturePaths, ...product.picturePaths] });
              }
            })
          );
        }
        return {...product, id: doc.id,  picturePaths: [...picturePaths, ...product.picturePaths] } as Product;
      });
    }
  }

  async updateProductQRsDB(brand: Brand, product: Product, clientIds: number[]) {
    const productQRInfos: ProductQRInfo[] = [...product.productQRs];
    clientIds.forEach(clientId => {
      this.qrService.addQRCode(clientId, product.id, brand.id).then(productQRInfo => {
        productQRInfos.push(productQRInfo);
        if (productQRInfos.length == clientIds.length) {
          this.getProductsCollectionRef(brand.id).doc(product.id).update({...product, productQRs: productQRInfos});
        }
      });
    });
    return {...product, productQRs: productQRInfos};
  }

  async editProduct(brand: Brand, product: Product, pictureFiles: File[], videoFile: File) {
    if (videoFile != null) {
      return this.fileService.uploadProductFile(brand.id, videoFile, product.id).then(videoPath => {
        const picturePaths: string[] = [];
        if (pictureFiles.length > 0) {
          pictureFiles
            .forEach(async file => await this.fileService.uploadProductFile(brand.id, file, product.id)
            .then(path => {
              picturePaths.push(path);
              if (pictureFiles.indexOf(file) === pictureFiles.length - 1) {
                this.updateProduct(brand, {...product, id: product.id, picturePaths: [...picturePaths, ...product.picturePaths], videoPath });
              }
            })
          );
        }
        return {...product,  picturePaths: [...picturePaths, ...product.picturePaths], videoPath } as Product;
      });

    } else {
      const picturePaths: string[] = [];
      if (pictureFiles.length > 0) {
        pictureFiles
          .forEach(async file => await this.fileService.uploadProductFile(brand.id, file, product.id)
          .then(path => {
            picturePaths.push(path);
            if (pictureFiles.indexOf(file) === pictureFiles.length - 1) {
              this.updateProduct(brand, {...product, id: product.id, picturePaths: [...picturePaths, ...product.picturePaths] });
            }
          })
        );
      }
      return {...product,  picturePaths: [...picturePaths, ...product.picturePaths] } as Product;
    }
  }

  async updateProduct(brand: Brand, product: Product) {
    return this.getProductsCollectionRef(brand.id).doc(product.id).update(product);
  }

  async deleteProduct(brand: Brand, product: Product) {
    return this.getProductsCollectionRef(brand.id).doc(product.id).delete();
  }

  private formatErrors(error: any) {
    return throwError(error.error);
  }
}
